282 std::pair<BasicBlock *, bool> ControlFlowHub::finalize(
283     DomTreeUpdater *DTU, SmallVectorImpl<BasicBlock *> &GuardBlocks,
284     const StringRef Prefix, std::optional<unsigned> MaxControlFlowBooleans) {
285 #ifndef NDEBUG
286   SmallPtrSet<BasicBlock *, 8> Incoming;
287 #endif
288   SetVector<BasicBlock *> Outgoing;
289 
290   for (auto [BB, Succ0, Succ1] : Branches) {
291 #ifndef NDEBUG
292     assert(
293         (Incoming.insert(BB).second || isa<CallBrInst>(BB->getTerminator())) &&
294         "Duplicate entry for incoming block.");
295 #endif
296     if (Succ0)
297       Outgoing.insert(Succ0);
298     if (Succ1)
299       Outgoing.insert(Succ1);
300   }
301 
302   if (Outgoing.size() < 2)
303     return {Outgoing.front(), false};
304 
305   SmallVector<DominatorTree::UpdateType, 16> Updates;
306   if (DTU) {
307     for (auto [BB, Succ0, Succ1] : Branches) {
308       if (Succ0)
309         Updates.push_back({DominatorTree::Delete, BB, Succ0});
310       // Only add Succ1 if it's different from Succ0 to avoid duplicate updates
311       if (Succ1 && Succ1 != Succ0)
312         Updates.push_back({DominatorTree::Delete, BB, Succ1});
313     }
314   }
315 
316   SmallVector<WeakVH, 8> DeletionCandidates;
317   convertToGuardPredicates(Branches, Outgoing.getArrayRef(), GuardBlocks,
318                            DeletionCandidates, Prefix, MaxControlFlowBooleans);
319   BasicBlock *FirstGuardBlock = GuardBlocks.front();
320 
321   // Update the PHINodes in each outgoing block to match the new control flow.
322   for (int I = 0, E = GuardBlocks.size(); I != E; ++I)
323     reconnectPhis(Outgoing[I], GuardBlocks[I], Branches, FirstGuardBlock);
324   // Process the Nth (last) outgoing block with the (N-1)th (last) guard block.
325   reconnectPhis(Outgoing.back(), GuardBlocks.back(), Branches, FirstGuardBlock);
326 
327   if (DTU) {
328     int NumGuards = GuardBlocks.size();
329 
330     for (auto [BB, Succ0, Succ1] : Branches)
331       Updates.push_back({DominatorTree::Insert, BB, FirstGuardBlock});
332 
333     for (int I = 0; I != NumGuards - 1; ++I) {
334       Updates.push_back({DominatorTree::Insert, GuardBlocks[I], Outgoing[I]});
335       Updates.push_back(
336           {DominatorTree::Insert, GuardBlocks[I], GuardBlocks[I + 1]});
337     }
338     // The second successor of the last guard block is an outgoing block instead
339     // of having a "next" guard block.
340     Updates.push_back({DominatorTree::Insert, GuardBlocks[NumGuards - 1],
341                        Outgoing[NumGuards - 1]});
342     Updates.push_back({DominatorTree::Insert, GuardBlocks[NumGuards - 1],
343                        Outgoing[NumGuards]});
344     DTU->applyUpdates(Updates);
345   }
346 
347   for (auto I : DeletionCandidates) {
348     if (I->use_empty())
349       if (auto *Inst = dyn_cast_or_null<Instruction>(I))
350         Inst->eraseFromParent();
351   }
352 
353   return {FirstGuardBlock, true};
354 }
