399 static bool FixIrreducibleImpl(Function &F, CycleInfo &CI, DominatorTree &DT,
400                                LoopInfo *LI) {
401   LLVM_DEBUG(dbgs() << "===== Fix irreducible control-flow in function: "
402                     << F.getName() << "\n");
403 
404   bool Changed = false;
405   for (Cycle *TopCycle : CI.toplevel_cycles()) {
406     for (Cycle *C : depth_first(TopCycle)) {
407       Changed |= fixIrreducible(*C, CI, DT, LI);
408     }
409   }
410 
411   if (!Changed)
412     return false;
413 
414 #if defined(EXPENSIVE_CHECKS)
415   CI.verify();
416   if (LI) {
417     LI->verify(DT);
418   }
419 #endif // EXPENSIVE_CHECKS
420 
421   return true;
422 }
